25: use style::stylesheets::layer_rule::LayerOrder;
26: use style::stylist::Stylist;
27: use style::values::computed::font::GenericFontFamily;
28: use style::values::computed::{Context, Length};
29: use style::values::specified::font::QueryFontMetricsFlags;
30: use test::{self, Bencher};
31: use url::Url;
32: 
33: #[derive(Debug)]
34: struct DummyMetricsProvider;
35: 
36: impl FontMetricsProvider for DummyMetricsProvider {
37:     fn query_font_metrics(
38:         &self,
39:         _vertical: bool,
40:         _font: &Font,
41:         _base_size: Length,
42:         _flags: QueryFontMetricsFlags,
43:     ) -> FontMetrics {
44:         Default::default()
45:     }
46:     fn base_size_for_generic(&self, _: GenericFontFamily) -> Length {
47:         Length::new(16.)
48:     }
49: }
50: 
51: fn cascade(
52:     name_and_value: &[(&str, &str)],
53:     inherited: &ComputedCustomProperties,
54: ) -> ComputedCustomProperties {
55:     let dummy_url_data = UrlExtraData::from(Url::parse("about:blank").unwrap());
56:     let declarations = name_and_value
57:         .iter()
58:         .map(|&(name, value)| {
59:             let mut input = ParserInput::new(value);
60:             let mut parser = Parser::new(&mut input);
61:             let name = Name::from(name);
62:             let value = CustomDeclarationValue::Unparsed(Arc::new(
63:                 SpecifiedValue::parse(&mut parser, &dummy_url_data).unwrap(),
64:             ));
65:             CustomDeclaration { name, value }
66:         })
67:         .collect::<Vec<_>>();
68: 
69:     let initial_style = ComputedValues::initial_values_with_font_override(Font::initial_values());
70:     let device = Device::new(
71:         MediaType::screen(),
72:         QuirksMode::NoQuirks,
73:         Size2D::new(800., 600.),
74:         Scale::new(1.0),
75:         Box::new(DummyMetricsProvider),
76:         initial_style,
77:         PrefersColorScheme::Light,
78:     );
79:     let stylist = Stylist::new(device, QuirksMode::NoQuirks);
80:     let mut builder = StyleBuilder::new(stylist.device(), Some(&stylist), None, None, None, false);
81:     builder.custom_properties = inherited.clone();
82:     let mut rule_cache_conditions = RuleCacheConditions::default();
83:     let mut context = Context::new(
84:         builder,
85:         stylist.quirks_mode(),
86:         &mut rule_cache_conditions,
87:         ContainerSizeQuery::none(),
88:     );
89:     let mut builder = CustomPropertiesBuilder::new(&stylist, &mut context);
90: 
91:     for declaration in &declarations {
92:         builder.cascade(
93:             declaration,
94:             CascadePriority::new(CascadeLevel::same_tree_author_normal(), LayerOrder::root()),
95:             &DummyAttributeProvider,
96:         );
97:     }
98: 
99:     builder.build(
100:         DeferFontRelativeCustomPropertyResolution::No,
101:         &DummyAttributeProvider,
102:     );
103:     context.builder.custom_properties
104: }
105: 
106: #[bench]
107: fn cascade_custom_simple(b: &mut Bencher) {
108:     b.iter(|| {
109:         let parent = cascade(
110:             &[("foo", "10px"), ("bar", "100px")],
111:             &ComputedCustomProperties::default(),
112:         );
113: 
114:         test::black_box(cascade(
115:             &[("baz", "calc(40em + 4px)"), ("bazz", "calc(30em + 4px)")],
116:             &parent,
117:         ))
118:     })
119: }
