28:   }, "containerName without query");
29: 
30:   test(() => {
31:     const rule = insertRule("@container (width > 300px) {}");
32:     assert_true(!!rule, "Rule successfully parsed");
33:     assert_equals(rule.containerName, "");
34:     assert_equals(rule.containerQuery, "(width > 300px)");
35:   }, "containerQuery without name");
36: 
37:   test(() => {
38:     const rule = insertRule("@container Name (width > 300px) {}");
39:     assert_true(!!rule, "Rule successfully parsed");
40:     assert_equals(rule.containerName, "Name");
41:     assert_equals(rule.containerQuery, "(width > 300px)");
42:   }, "containerName and containerQuery");
